# Category: edge_computing_security

import requests
from aws_lambda_edge import event, context

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    # Check if X-Enrich-URL header is present
    if 'x-enrich-url' in headers:
        enrich_url = headers['x-enrich-url'][0]['value']

        # Make HTTP request to enrich data
        response = requests.get(enrich_url)

        # Parse and store enriched data in request object
        request['body'] = response.content

    return request